14	    expect(out).toEqual({ results: [{ premium: 115 }] });
15	  });
16	  it("quote for a single plain amulet (new customer, 1st contract) → 60 base + 6 first-ins + 5 fee = 71 G", () => {
17	    const out = run({ customer: { yearsWithMHPCO: 0 }, steps: [{ op: "quote", items: [{ type: "amulet" }] }] });
18	    expect(out).toEqual({ results: [{ premium: 71 }] });
19	  });
20	  it("quote for a single plain staff (new customer, 1st contract) → 80 base + 8 first-ins + 5 fee = 93 G", () => {
21	    const out = run({ customer: { yearsWithMHPCO: 0 }, steps: [{ op: "quote", items: [{ type: "staff" }] }] });
22	    expect(out).toEqual({ results: [{ premium: 93 }] });
23	  });
24	  it("quote for a single plain potion (new customer, 1st contract) → 40 base + 4 first-ins + 5 fee = 49 G", () => {
25	    const out = run({ customer: { yearsWithMHPCO: 0 }, steps: [{ op: "quote", items: [{ type: "potion" }] }] });
26	    expect(out).toEqual({ results: [{ premium: 49 }] });
27	  });
28	
29	  // --- Components base premium (per-component default) ---
30	  it("quote for 2 runes (new customer, 1st contract) → 50 base + 5 first-ins + 5 fee = 60 G", () => {
31	    const out = run({ customer: { yearsWithMHPCO: 0 }, steps: [{ op: "quote", items: [{ type: "rune" }, { type: "rune" }] }] });
32	    expect(out).toEqual({ results: [{ premium: 60 }] });
33	  });
34	
35	  // --- Building block of 3 alike components ---
36	  it("quote for 3 runes (block) (new customer, 1st contract) → 60 base + 6 first-ins + 5 fee = 71 G", () => {
37	    const out = run({ customer: { yearsWithMHPCO: 0 }, steps: [{ op: "quote", items: [{ type: "rune" }, { type: "rune" }, { type: "rune" }] }] });
38	    expect(out).toEqual({ results: [{ premium: 71 }] });
39	  });
40	  it("quote for 4 runes (no block) → 100 base + 10 first-ins + 5 fee = 115 G", () => {
41	    const out = run({ customer: { yearsWithMHPCO: 0 }, steps: [{ op: "quote", items: [{ type: "rune" }, { type: "rune" }, { type: "rune" }, { type: "rune" }] }] });
42	    expect(out).toEqual({ results: [{ premium: 115 }] });
43	  });
44	  it("quote for 7 runes (no block — block requires exactly 3) → 175 base + 18 first-ins + 5 fee = 198 G", () => {
45	    const out = run({
46	      customer: { yearsWithMHPCO: 0 },
47	      steps: [{ op: "quote", items: Array(7).fill({ type: "rune" }) }],
48	    });
49	    expect(out).toEqual({ results: [{ premium: 198 }] });
50	  });
51	
52	  // --- 'Alike' components clarified by type ---
53	  it("quote for 2 runes + 1 moonstone (no block: different types) → 75 base + 8 first-ins + 5 fee = 88 G", () => {
54	    const out = run({
55	      customer: { yearsWithMHPCO: 0 },
56	      steps: [{ op: "quote", items: [{ type: "rune" }, { type: "rune" }, { type: "moonstone" }] }],
57	    });
58	    expect(out).toEqual({ results: [{ premium: 88 }] });
59	  });
60	  it("quote for 3 runes + 3 moonstones (two separate blocks) → 120 base + 12 first-ins + 5 fee = 137 G", () => {
61	    const out = run({
62	      customer: { yearsWithMHPCO: 0 },
63	      steps: [{ op: "quote", items: [
64	        { type: "rune" }, { type: "rune" }, { type: "rune" },
65	        { type: "moonstone" }, { type: "moonstone" }, { type: "moonstone" },
66	      ] }],
67	    });
68	    expect(out).toEqual({ results: [{ premium: 137 }] });
69	  });
70	
71	  // --- Single-modifier surcharges/discounts on a single item ---
72	  it.todo("cursed sword alone (new customer, 1st contract) → 100 base + 50 curse + 10 first-ins + 5 fee = 165 G");
73	  it.todo("high-enchantment sword (enchantment 5) alone (new customer, 1st contract) → 100 + 30 + 10 + 5 = 145 G");
74	  it.todo("sword with enchantment 4 alone (new customer, 1st contract) → no high-ench surcharge → 115 G");
75	
76	  // --- Modifier thresholds ---
77	  it.todo("customer with exactly 2 years gets loyalty discount (plain sword, 1st contract) → 100 - 20 + 10 + 5 = 95 G");
78	  it.todo("cursed sword with exactly enchantment 5 gets both surcharges → 100 + 50 + 30 + 10 + 5 = 195 G");
79	
80	  // --- Multi-item policy & modifier scope ---
81	  it.todo("cursed sword + plain amulet (new customer, 1st contract) → 100+60 base, cursed adds 50 (of sword only), first-ins 10% of policy total → 160 + 50 + 16 + 5 = 231 G");
82	
83	  // --- Follow-up contract discount (15% on each contract after first) ---
84	  it.todo("second quote in scenario: cursed sword + plain amulet, 0 years → first ins still 10%, follow-up 15% off policy total");
85	
86	  // --- Integration examples ---
87	  it.todo("newcomer cursed sword (0 years, no prior): 100 + 50 + 10 + 5 = 165 G");
88	  it.todo("long-standing customer's 2nd contract, cursed enchantment-7 sword (3 years): 100 + 50 + 30 - 20 + 10 - 15 + 5 = 160 G");
89	
90	  // --- Rounding in MHPCO's favor ---
91	  it.todo("premium calculation yielding 197.5 G → final premium 198 G (rounded up)");
92	
93	  // --- Claim: basic deductible & standard reimbursement ---
94	  it.todo("steel sword enchantment 3, damage 500 → payout 400 (500 - 100 deductible)");
95	  it.todo("damage to a rune (250 G), damage 200 → payout 100 (200 - 100 deductible)");
96	
97	  // --- Claim: high-enchantment 50% clause ---
98	  it.todo("steel sword enchantment 9, damage 1000 → payout 400 (50% then deductible: 500 - 100)");
99	
100	  // --- Claim: dragon material full reimbursement ---
101	  it.todo("dragon-material sword enchantment 5, damage 800 → payout 700 (full minus deductible)");
102	
103	  // --- Claim: dragon + high enchantment combined (50% wins) ---
104	  it.todo("dragon-material sword enchantment 8, damage 1000 → payout 400 (high-ench applies first then deductible)");
105	  it.todo("dragon-material sword enchantment 9, damage 1000 → payout 400 (50% rule wins, then deductible)");
106	
107	  // --- Claim: deductible per damage event ---
108	  it.todo("dragon attack damages insured sword 500 and amulet 300 → payout 600 (deductible applies once per damaged item)");
109	
110	  // --- Multiple items of same type ---
111	  it.todo("policy with two swords: insurance sum 2000 G, cap 4000 G; two sword damage entries each get own deductible");
112	  it.todo("claim with more sword damages than swords insured → CLI exits non-zero (claim rejected)");
113	
114	  // --- Cap exhaustion ---
115	  it.todo("sword + amulet policy → insurance sum 1600 G, cap 3200 G");
116	  it.todo("cursed sword cap is 2000 G (based on unmodified insurance value, premium modifiers do not raise cap)");
117	  it.todo("sword + 3 runes block: insurance sum 1750 G (block discount affects premium only, not insurance sum)");
118	  it.todo("sword (cap 2000): claim 1500 → payout 1400, remainingCap 600; second claim 1500 → payout 600, remainingCap 0");
119	
120	  // --- Rounding payout ---
121	  it.todo("payout calculation yielding 350.5 G → final payout 350 G (rounded down)");
122	
123	  // --- Error cases ---
124	  it.todo("quote with unknown item type (e.g. broomstick) → CLI exits non-zero with error to stderr");
125	  it.todo("claim references damage entry whose item is not in policy → CLI exits non-zero");
126	  it.todo("claim contains damage entry with negative amount → CLI exits non-zero");
127	});
